class SendgridMailer < ApplicationMailer
  def deliver_email(to:, subject:, html_body: nil, text_body: nil, from: nil, categories: [], custom_args: {})
    @html_body = html_body
    @text_body = text_body

    headers["X-SMTPAPI"] = {
      category: Array(categories),
      unique_args: custom_args.transform_keys(&:to_s)
    }.to_json

    mail(
      to: to,
      from: from || default_params[:from],
      subject: subject
    ) do |format|
      format.html { render html: @html_body.to_s.html_safe } if @html_body.present?
      format.text { render plain: @text_body.to_s } if @text_body.present?
      if @html_body.blank? && @text_body.blank?
        format.text { render plain: "" }
      end
    end
  end
end

